class Solution {
public:
    int divide(int dividend, int divisor) {
        // Handle the overflow case explicitly
        if (dividend == INT_MIN && divisor == -1) {
            return INT_MAX;
        }
        if (dividend == INT_MAX && divisor == 1) {
            return INT_MAX;
        }
        if ((dividend == INT_MAX && divisor == -1) || (dividend == INT_MIN && divisor == 1)) {
            return INT_MIN;
        }

        if (dividend == divisor)
            return 1;

        bool end_neg = dividend < 0;
        bool sor_neg = divisor < 0;

        // Use long long to avoid overflow when converting to positive
        long long ldividend = dividend;
        long long ldivisor = divisor;

        if (end_neg) {
            ldividend = -ldividend;
        }
        if (sor_neg) {
            ldivisor = -ldivisor;
        }

        if (ldividend < ldivisor)
            return 0;

        int n_max = binarySearch(ldividend, ldivisor);
        long long result = divide(ldividend, ldivisor, n_max, 0);

        if (end_neg ^ sor_neg) {
            result = -result;
        }

        // Ensure result is within int range
        if (result > INT_MAX) return INT_MAX;
        if (result < INT_MIN) return INT_MIN;

        return (int)result;
    }

private:
    long long divide(long long dividend, long long divisor, int n, long long total) {
        if(n < 0) return total;

        long long shiftedDivisor = divisor << n;

        if(dividend < shiftedDivisor){
            return divide(dividend, divisor, n - 1, total);
        }
        else{
            return divide(dividend - shiftedDivisor, divisor, n - 1, total + (1LL << n));
        }
    }

    int binarySearch(long long dividend, long long divisor) {
        int low = 0;
        int high = 30; // Reduced from 31 to avoid overflow
        int result = -1;

        while (low <= high) {
            int mid = low + (high - low) / 2;

            long long shifted = divisor << mid;

            if (shifted <= dividend) {
                result = mid;
                // Check if we can go higher without overflow
                if (mid < 30 && (divisor << (mid + 1)) <= dividend) {
                    low = mid + 1;
                } else {
                    break;
                }
            } else {
                high = mid - 1;
            }
        }

        return result;
    }

    bool check_equal(long long dividend, long long divisor, int n){
        if (n >= 30) return false; // Avoid overflow

        long long current = divisor << n;
        long long next = divisor << (n + 1);

        return (current <= dividend && dividend < next);
    }

    bool check_greater(long long dividend, long long divisor, int n){
        if (n >= 31) return true; // Avoid overflow
        return dividend < (divisor << n);
    }
};

